import{_ as e,o as a,c as t,a as i}from"./app.9c50e1ca.js";const u=JSON.parse('{"title":"Yoahtl v. 1machinemaker1, Nov 2017","description":"","frontmatter":{},"headers":[{"level":2,"title":"Charges","slug":"charges","link":"#charges","children":[]},{"level":2,"title":"Plea","slug":"plea","link":"#plea","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]},{"level":2,"title":"Outcome","slug":"outcome","link":"#outcome","children":[]}],"relativePath":"government/court-cases-precedents/yoahtl_v_1machinemaker1_nov_2017.md","lastUpdated":1662860591000}'),r={name:"government/court-cases-precedents/yoahtl_v_1machinemaker1_nov_2017.md"},n=i('<h1 id="yoahtl-v-1machinemaker1-nov-2017" tabindex="-1">Yoahtl v. 1machinemaker1, Nov 2017 <a class="header-anchor" href="#yoahtl-v-1machinemaker1-nov-2017" aria-hidden="true">#</a></h1><p><strong>Judge</strong>: Klasikrok</p><p><strong>Date</strong>: 5th November 2017</p><h2 id="charges" tabindex="-1">Charges <a class="header-anchor" href="#charges" aria-hidden="true">#</a></h2><ol><li><p>Disorderly conduct</p></li><li><p>Grief</p></li><li><p>Insubordination</p></li></ol><h2 id="plea" tabindex="-1">Plea <a class="header-anchor" href="#plea" aria-hidden="true">#</a></h2><ol><li><p>Not guilty by reason of meming not being a crime</p></li><li><p>Not guilty by reason of fulfilling a task contracted by the owner of the property</p></li><li><p>Not guilty by reason of not having been issued orders by a public official</p></li></ol><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><ul><li><p>1machinemaker1 denies all charges</p></li><li><p>Fran submits evidence but declines to directly testify</p></li><li><p>Klasikrok attempts to drop the charge of insubordination</p></li><li><p>TheOrangeWizard objects, claims that he did ask 1machinemaker1 to stop activity on the water drop to Fran&#39;s storage</p></li><li><p>Prosecution presents the following screenshot as evidence of 1machinemaker1&#39;s grief of Fran&#39;s storage: <a href="https://cdn.discordapp.com/attachments/348687557455904778/377611331592912906/2017-11-05_03.57.01.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/377611331592912906/2017-11-05_03.57.01.png</a></p></li><li><p>1machinemaker1 claims this was before it was finished, therefore not evidence of permanent grief</p></li><li><p>Prosecution asks 1machinemaker1 to explain this screenshot: <a href="https://cdn.discordapp.com/attachments/348687557455904778/377613246833885185/2017-11-06_17.04.12.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/377613246833885185/2017-11-06_17.04.12.png</a></p></li><li><p>1machinemaker1 claims this was a temporary drop used during construction and to prevent deaths via falling into unfinished drops</p></li><li><p>Prosecution asks 1machinemaker1 to explain this screenshot: <a href="https://cdn.discordapp.com/attachments/348687557455904778/377613246833885185/2017-11-06_17.04.12.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/377613246833885185/2017-11-06_17.04.12.png</a></p></li><li><p>1machinemaker1 claims he didn&#39;t place this particular structure</p></li><li><p>Prosecution presents the following screenshot: <a href="https://cdn.discordapp.com/attachments/348687557455904778/377619319619846145/2017-11-05_22.51.15.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/377619319619846145/2017-11-05_22.51.15.png</a></p></li><li><p>1machinemaker1 denies culpability again</p></li><li><p>1machinemaker1 is found guilty of grief, admits to having been asked to stop by Fran (implicating him in charges of disorderly conduct for refusal to follow Fran&#39;s instructions)</p></li><li><p>1machinemaker1 attempts to appeal</p></li><li><p>Charges of grief dropped</p></li><li><p>1machinemaker1 found guilty of insubordination</p></li><li><p>appeal denied by TheOrangeWizard</p></li></ul><h2 id="outcome" tabindex="-1">Outcome <a class="header-anchor" href="#outcome" aria-hidden="true">#</a></h2><ul><li><p>Not guilty</p></li><li><p>Not guilty</p></li></ul>',11),o=[n];function s(l,c,p,h,d,m){return a(),t("div",null,o)}const f=e(r,[["render",s]]);export{u as __pageData,f as default};
